def load_translations(lang: str) -> dict:
    path = os.path.join(_TRANS_DIR, f"{lang}.json")
    try:
        with open(path, encoding="utf-8") as f:
            data = json.load(f)
    except FileNotFoundError:
        data = {}
    # Merge extra keys (guide section not present in baked-image JSON)
    extra = _GUIDE_EXTRA.get(lang, {})
    for section, vals in extra.items():
        if section not in data:
            data[section] = {}
        if isinstance(vals, dict):
            data[section].update(vals)
        else:
            data[section] = vals
    return data


def get_translator(lang: str):
    """t(key, **kwargs) 함수를 반환. key는 점(.) 구분자 사용."""
    if lang not in SUPPORTED:
        lang = DEFAULT
    translations = load_translations(lang)

    def t(key: str, **kwargs) -> str:
        parts = key.split(".")
        val = translations
        for p in parts:
            if isinstance(val, dict):
                val = val.get(p, key)
            else:
                return key
        if not isinstance(val, str):
            return key
        for k, v in kwargs.items():
            val = val.replace("{{" + k + "}}", str(v))
        return val

    return t


def detect_lang(cookie_lang: str, accept_language: str) -> str:
    """쿠키 > Accept-Language > 기본값(ko) 순으로 언어 감지"""
    if cookie_lang in SUPPORTED:
        return cookie_lang
    if accept_language:
        al = accept_language.lower()
        if al.startswith("en"):
            return "en"
    return DEFAULT
